noncompliant:
class Base {
  virtual void fun();
};

class Derived final : Base {
  void fun() final; // Noncompliant - redundant final in final class
};

union MyUnion final { // Noncompliant - final is redundant for unions
  int a;
  double b;
};

compliant:
class Base {
  virtual void fun();
};

class Derived final : Base {
  void fun() override; // Compliant - use override instead
};

union MyUnion { // Compliant - no unnecessary final
  int a;
  double b;
};
